11	/** Escape pipe characters so they don't break markdown table columns. */
12	const escapePipes = (text: string): string => text.replace(/\|/g, "\\|");
13	
14	/** Replace backticks so they don't break inline code spans. */
15	const escapeCodeBackticks = (text: string): string => text.replace(/`/g, "-");
