35	/** Tally findings by severity for the summary counts line. Ignores out-of-domain severities. */
36	export const computeSeverityCounts = (findings: readonly Finding[]): SeverityCounts =>
37	  findings.reduce<Record<Severity, number>>(
38	    (acc, f) => (f.severity in acc ? { ...acc, [f.severity]: acc[f.severity] + 1 } : acc),
